def lcs_length(a, b):
    # simple dynamic programming LCS length; beware of long strings; but this is manageable
    n, m = len(a), len(b)
    # Use memory-optimized DP? We'll do normal, lengths maybe 400, ok.
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n):
        ai = a[i]
        for j in range(m):
            if ai == b[j]:
                dp[i+1][j+1] = dp[i][j] + 1
            else:
                dp[i+1][j+1] = dp[i+1][j] if dp[i+1][j] >= dp[i][j+1] else dp[i][j+1]
    return dp[n][m]

